import{_ as o,a as t,a3 as a,o as r}from"./chunks/framework.edeurCMZ.js";const h=JSON.parse('{"title":"HPCC Systems 10.4.0.0 Platform Release Announcement","description":"","frontmatter":{},"headers":[],"relativePath":"devdoc/release_announcements/10.4-Platform-Release-Announcement.md","filePath":"devdoc/release_announcements/10.4-Platform-Release-Announcement.md","lastUpdated":1782747484000}'),n={name:"devdoc/release_announcements/10.4-Platform-Release-Announcement.md"};function l(s,e,i,c,d,m){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="hpcc-systems-10-4-0-0-platform-release-announcement" tabindex="-1">HPCC Systems 10.4.0.0 Platform Release Announcement <a class="header-anchor" href="#hpcc-systems-10-4-0-0-platform-release-announcement" aria-label="Permalink to &quot;HPCC Systems 10.4.0.0 Platform Release Announcement&quot;">​</a></h1><p>This release delivers improvements in <strong>cloud storage behavior (AWS S3)</strong>, <strong>operability and diagnostics</strong>, and <strong>deployment/configuration flexibility</strong> across the HPCC Systems Platform.</p><p>Highlights include enhancements to the AWS S3 implementation, new scope filtering in XRef, expanded event recording for troubleshooting, improvements to packaging workflows, and <strong>new client tools to accelerate ECL development from JSON/XML inputs</strong>.</p><h2 id="performance-improvements" tabindex="-1">Performance Improvements <a class="header-anchor" href="#performance-improvements" aria-label="Permalink to &quot;Performance Improvements&quot;">​</a></h2><h3 id="cloud-storage-aws-s3" tabindex="-1">Cloud Storage (AWS S3) <a class="header-anchor" href="#cloud-storage-aws-s3" aria-label="Permalink to &quot;Cloud Storage (AWS S3)&quot;">​</a></h3><ul><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/20699" target="_blank" rel="noreferrer">HPCC-35296 Improve AWS S3 implementation</a> — Improves the AWS S3 integration and overall behavior in S3-backed environments.</li></ul><h2 id="notable-changes-and-features" tabindex="-1">Notable Changes and Features <a class="header-anchor" href="#notable-changes-and-features" aria-label="Permalink to &quot;Notable Changes and Features&quot;">​</a></h2><h3 id="client-tools-developer-productivity" tabindex="-1">Client Tools / Developer Productivity <a class="header-anchor" href="#client-tools-developer-productivity" aria-label="Permalink to &quot;Client Tools / Developer Productivity&quot;">​</a></h3><ul><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/21090" target="_blank" rel="noreferrer">HPCC-35980 New client tools: json2ecl and xml2ecl</a> — Adds two new client utilities, <code>json2ecl</code> and <code>xml2ecl</code>, to help convert JSON/XML into ECL more quickly and consistently.</li><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/21177" target="_blank" rel="noreferrer">HPCC-35986 Document json2ecl xml2ecl Client Tools</a> — Adds documentation for the new <code>json2ecl</code> / <code>xml2ecl</code> tools to support adoption and correct usage.</li></ul><h3 id="cross-reference-xref" tabindex="-1">Cross-Reference (XRef) <a class="header-anchor" href="#cross-reference-xref" aria-label="Permalink to &quot;Cross-Reference (XRef)&quot;">​</a></h3><ul><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/20609" target="_blank" rel="noreferrer">HPCC-35248 Add scope filters to XRef</a> — Adds scope filtering to XRef to help operators narrow analysis and improve usability on larger systems.</li></ul><h3 id="observability-event-recording" tabindex="-1">Observability / Event Recording <a class="header-anchor" href="#observability-event-recording" aria-label="Permalink to &quot;Observability / Event Recording&quot;">​</a></h3><ul><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/20994" target="_blank" rel="noreferrer">HPCC-35848 Add an IndexOpen event to the event recording</a> — Adds an <code>IndexOpen</code> event to recorded telemetry to support troubleshooting and analysis.</li><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/20953" target="_blank" rel="noreferrer">HPCC-35637 Add RecordingSource events to Roxie and ESP</a> — Extends event recording in Roxie and ESP with additional <code>RecordingSource</code> events for better traceability.</li></ul><h3 id="indexing-and-compression-controls" tabindex="-1">Indexing and Compression Controls <a class="header-anchor" href="#indexing-and-compression-controls" aria-label="Permalink to &quot;Indexing and Compression Controls&quot;">​</a></h3><ul><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/21098" target="_blank" rel="noreferrer">HPCC-35992 Allow index nodesize to be set in the compression string</a> — Adds configurability for index node sizing via the compression string, enabling more control over index storage/behavior.</li></ul><h3 id="tooling-and-developer-workflow" tabindex="-1">Tooling and Developer Workflow <a class="header-anchor" href="#tooling-and-developer-workflow" aria-label="Permalink to &quot;Tooling and Developer Workflow&quot;">​</a></h3><ul><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/21071" target="_blank" rel="noreferrer">HPCC-31731 Add ecl --poll support when compiling workunits</a> — Adds <code>--poll</code> support to the <code>ecl</code> CLI when compiling workunits, improving command-line workflow automation and visibility.</li><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/21014" target="_blank" rel="noreferrer">HPCC-35907 Add option to testsocket to request summary stats</a> — Extends <code>testsocket</code> with an option to request summary statistics for easier diagnostics.</li></ul><h3 id="platform-and-deployment" tabindex="-1">Platform and Deployment <a class="header-anchor" href="#platform-and-deployment" aria-label="Permalink to &quot;Platform and Deployment&quot;">​</a></h3><ul><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/20900" target="_blank" rel="noreferrer">HPCC-35715 Add the option to specify a target plane to package services</a> — Adds support for specifying a target plane when packaging services, improving deployment flexibility.</li><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/20899" target="_blank" rel="noreferrer">HPCC-35718 Allow package maps to include files that are not in superfiles</a> — Allows package maps to include files not contained in superfiles, broadening packaging options.</li><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/20986" target="_blank" rel="noreferrer">HPCC-35845 Add roxieMode and transportProtocol to the values schema</a> — Adds <code>roxieMode</code> and <code>transportProtocol</code> to the values schema to support more explicit configuration.</li></ul><h3 id="documentation-updates" tabindex="-1">Documentation Updates <a class="header-anchor" href="#documentation-updates" aria-label="Permalink to &quot;Documentation Updates&quot;">​</a></h3><ul><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/20996" target="_blank" rel="noreferrer">HPCC-35859 Document index default compression options</a> — Documents default index compression options for clearer operational guidance.</li><li><a href="https://github.com/hpcc-systems/HPCC-Platform/pull/21177" target="_blank" rel="noreferrer">HPCC-35986 Document json2ecl xml2ecl Client Tools</a> — Adds documentation for the new <code>json2ecl</code> / <code>xml2ecl</code> tools to support adoption and correct usage.</li></ul><h2 id="additional-notes" tabindex="-1">Additional Notes <a class="header-anchor" href="#additional-notes" aria-label="Permalink to &quot;Additional Notes&quot;">​</a></h2><p>For more details, follow the linked pull requests in each section.</p>',23)])])}const u=o(n,[["render",l]]);export{h as __pageData,u as default};
